function solve(nums, k) {
    const n = nums.length;

    if (n === 0) {
        return 0;
    }

    // dp[i][state] stores the maximum score of a valid subsequence ending at index i.
    // state 0: nums[i] is the smaller element in the last pair (i.e., sequence ends with ... < nums[i])
    // state 1: nums[i] is the larger element in the last pair (i.e., sequence ends with ... > nums[i])
    // Since a sequence of length 1 is valid, we need to handle this initialization.
    // We use a slightly different DP state to handle the alternating pattern more easily.

    // Let dp[i][0] be the maximum score of a valid subsequence ending at index i,
    // where nums[i] is the minimum in the last transition (i.e., sequence ends with ... > nums[i] < ...).
    // More precisely:
    // dp[i][0]: Max score ending at i, where the element before nums[i] (if exists) was GREATER than nums[i]. (Pattern: ... > nums[i])
    // dp[i][1]: Max score ending at i, where the element before nums[i] (if exists) was SMALLER than nums[i]. (Pattern: ... < nums[i])

    // Wait, the definition of alternating sequence depends on the *next* element or the *previous* element.
    // Let's redefine based on the relation to the *previous* element in the chosen subsequence:

    // dp[i][0]: Max score of a valid subsequence ending at index i, such that the required next element must be > nums[i] (i.e., current element is a 'valley' or start of increasing trend: ... > nums[i] < ...)
    // This means the sequence ends in an UP trend, or it's the start. (e.g., nums[i-1] > nums[i] or length 1)
    // If length is 1, it's both a valley and a peak in terms of transition requirements for the next element.

    // Let's use the standard definition for alternating sequences:
    // dp[i][0]: Max score of an alternating subsequence ending at i, where nums[i] is the "peak" (nums[i-1] < nums[i]).
    // dp[i][1]: Max score of an alternating subsequence ending at i, where nums[i] is the "valley" (nums[i-1] > nums[i]).

    // Base case: Any single element subsequence [nums[i]] has a score of nums[i].
    // A single element can be considered both a peak and a valley for future extensions, but we must choose one interpretation for the DP transition.

    // Initialize dp[i][0] and dp[i][1] to nums[i], as a length-1 subsequence is always valid.
    const dp = Array(n).fill(0).map(() => [0, 0]);
    let maxScore = 0;

    for (let i = 0; i < n; i++) {
        // Base case: subsequence of length 1
        dp[i][0] = nums[i]; // Can be treated as a peak/start
        dp[i][1] = nums[i]; // Can be treated as a valley/start
        maxScore = Math.max(maxScore, nums[i]);

        // Iterate over all possible previous elements j < i
        for (let j = 0; j < i; j++) {
            if (i - j >= k) {
                const val_i = nums[i];
                const val_j = nums[j];

                // Case 1: nums[i] is a peak (current transition is increasing: nums[j] < nums[i])
                // To form ... < nums[j] < nums[i], the subsequence ending at j must have ended in a valley (dp[j][1]).
                if (val_j < val_i) {
                    dp[i][0] = Math.max(dp[i][0], dp[j][1] + val_i);
                }

                // Case 2: nums[i] is a valley (current transition is decreasing: nums[j] > nums[i])
                // To form ... > nums[j] > nums[i], the subsequence ending at j must have ended in a peak (dp[j][0]).
                if (val_j > val_i) {
                    dp[i][1] = Math.max(dp[i][1], dp[j][0] + val_i);
                }

                // Note on strict alternation:
                // If we are at dp[i][0] (peak: ... < nums[i]), the previous element nums[j] must be a valley (dp[j][1]).
