                // Valley -> Peak (dp[j][1] -> dp[i][0]) requires val_j < val_i

                // Wait, the definitions above are slightly mismatched with the typical alternating sequence structure:
                // Pattern 1: Up, Down, Up, Down... (e.g., < > < >)
                // Pattern 2: Down, Up, Down, Up... (e.g., > < > <)

                // Let's use the definitions that capture the required *next* step for simpler transition logic:
                // dp[i][0]: Max score ending at i, where the sequence must continue by going UP (i.e., nums[i] was a valley or start). (Pattern ... > nums[i] < ...)
                // dp[i][1]: Max score ending at i, where the sequence must continue by going DOWN (i.e., nums[i] was a peak or start). (Pattern ... < nums[i] > ...)

                // Re-evaluation with new state definitions:
                // dp[i][0] (Valley/Start): To reach here, the previous element nums[j] must have been a peak (dp[j][1]).
                // Transition: nums[j] > nums[i]
                if (val_j > val_i) {
                    dp[i][0] = Math.max(dp[i][0], dp[j][1] + val_i);
                }

                // dp[i][1] (Peak/Start): To reach here, the previous element nums[j] must have been a valley (dp[j][0]).
                // Transition: nums[j] < nums[i]
                if (val_j < val_i) {
                    dp[i][1] = Math.max(dp[i][1], dp[j][0] + val_i);
                }
            }
        }

        // Update maxScore considering all possibilities ending at i
        maxScore = Math.max(maxScore, dp[i][0], dp[i][1]);
    }

    return maxScore;
}

